CustomField.formula:
/* uncomment next and last 2 lines to handle negatives and denote them in accounting style -1234 == (1,234.00) */
/* SUBSTITUTE(
IF(Upsell_Amount__c< 0, "(", "") & */
/* uncomment and adjust currency sign */
/* "$" & */
IF(ABS( Upsell_Amount__c) >= 1000000, TEXT(FLOOR(Upsell_Amount__c/ 1000000)) & ",", "")
& IF(ABS(Upsell_Amount__c) >= 1000, RIGHT(TEXT(FLOOR(Upsell_Amount__c/ 1000)), 3) & ",", "")
& RIGHT(TEXT(FLOOR(Upsell_Amount__c)), 3)
/* multiplier x100 and 2 indicate number of decimal places */
& "." & RIGHT(TEXT(ROUND(Upsell_Amount__c* 100, 0)), 2)
/* & IF(Upsell_Amount__c< 0, ")", "")
,"-","") */

&
" " & Text ( Currency__c )
